#include<bits/stdc++.h>
using namespace std;
int n,tmp,l,r,f;
struct node
{
	int x,y;
	vector<int>v;
}a[100055];
map<int,int>mp;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].x>>a[i].y;
		for(int j=1;j<=a[i].y;j++)
		{
			cin>>tmp;
			a[i].v.push_back(tmp);
		}
	}
//	for(int i=1;i<=n;i++)
//	{
//		cout<<a[i].x<<" "<<a[i].y<<"\n";
//		for(int j=0;j<a[i].y;j++)
//		{
//			cout<<a[i].v[j]<<" ";
//		}
//		cout<<"\n";
//	}
	l=1;
	r=1;
	while(l<=n and r<=n and l<=r)
	{
//		cout<<l<<" "<<r<<" "<<a[3].y<<" ";
		for(int i=0;i<a[r].y;i++)
		{
			if(mp[a[r].v[i]]==0)	f++;
			mp[a[r].v[i]]++;
//			cout<<"A";
		}
//		cout<<f<<" "<<a[l].x<<" "<<a[r].x-86400<<"\n";
		while(l<=n and a[l].x<=a[r].x-86400)
		{
			for(int i=0;i<a[l].y;i++)
			{
//				cout<<mp[a[l].v[i]]<<" ";
				if(mp[a[l].v[i]]==1)	f--;
				mp[a[l].v[i]]--;
			}
			l++;
		}
//		l++;
		r++;
		cout<<f<<"\n";
	}
	return 0;
}
